xpath.script:
(function () {
    "use strict";

    // ---- v3.10.24: re-inject !important icon override CSS ----
    // The modal's IIFE (in payment_delivery_redesign.xml) only
    // runs on /shop/payment. The footer is on EVERY page, so
    // we re-inject the same !important rules here with an id
    // check to prevent double-injection. This guarantees the
    // cabang marker icon stays upright on mobile across all
    // pages, not just /shop/payment.
    (function injectMarkerStyleOverrides() {
        if (document.getElementById('wl-marker-icon-override')) return;
        var style = document.createElement('st' + 'yle');
        style.id = 'wl-marker-icon-override';
        style.textContent =
            '.wl-map-modal .wl-cabang-marker__pin .fa,' +
            '.wl-map-modal .wl-map-marker__pin .fa,' +
            '.wl-footer-map-embed .wl-cabang-marker__pin .fa,' +
            '.wl-footer-map-embed .wl-map-marker__pin .fa {' +
                'position: absolute !important;' +
                'top: 50% !important;' +
                'left: 50% !important;' +
                'transform: translate(-50%, -50%) rotate(45deg) !important;' +
            '}' +
            'body .wl-cabang-marker__pin .fa,' +
            'body .wl-map-marker__pin .fa {' +
                'transform: translate(-50%, -50%) rotate(45deg) !important;' +
            '}';
        document.head.appendChild(style);
        console.log('WL: footer marker icon !important overrides injected');
    })();

    // ---- v3.10.25: force popup text color to dark grey ----
    // Odoo theme rule `.o_cc5, .o_footer { color: #fff; }` makes
    // .maplibregl-popup-content (which is rendered inside the
    // footer) inherit WHITE text on WHITE background. The popup
    // LABELS survive because they have explicit color:#666 spans,
    // but the VALUES (kategori text, jarak number) are unwrapped
    // text nodes that inherit white and become INVISIBLE.
    // Fix: JS-inject !important rule forcing popup-content and its
    // children to dark grey. Same bypass technique as v3.10.22
    // (SCSS compiler can't strip !important from JS-injected CSS).
    (function injectPopupColorOverride() {
        if (document.getElementById('wl-popup-color-override')) return;
        var style = document.createElement('st' + 'yle');
        style.id = 'wl-popup-color-override';
        style.textContent =
            // Force dark text on popup container (covers unwrapped text nodes)
            '.maplibregl-popup-content {' +
                'color: #333 !important;' +
                'background: #fff !important;' +
            '}' +
            // Defensive: any descendant that doesn't have explicit color
            '.maplibregl-popup-content div:not([style*="color"]),' +
            '.maplibregl-popup-content span:not([style*="color"]),' +
            '.maplibregl-popup-content p:not([style*="color"]) {' +
                'color: #333 !important;' +
            '}' +
            // Legend overlay styling (added in v3.10.25)
            '.wl-footer-map-legend {' +
                'position: absolute;' +
                'bottom: 8px;' +
                'left: 8px;' +
                'z-index: 5;' +
                'background: rgba(255,255,255,0.96);' +
                'border: 1px solid #7a0c14;' +
                'border-radius: 6px;' +
                'padding: 6px 8px;' +
                'font-family: Poppins, sans-serif;' +
                'font-size: 10px;' +
                'line-height: 1.5;' +
                'color: #333;' +
                'box-shadow: 0 2px 6px rgba(0,0,0,0.15);' +
                'max-width: 140px;' +
                'pointer-events: none;' +
            '}' +
            '.wl-footer-map-legend__title {' +
                'font-weight: 700;' +
                'color: #7a0c14;' +
                'font-size: 10px;' +
                'text-transform: uppercase;' +
                'letter-spacing: 0.4px;' +
                'margin-bottom: 3px;' +
                'display: block;' +
            '}' +
            '.wl-footer-map-legend__row {' +
                'display: flex;' +
                'align-items: center;' +
                'gap: 5px;' +
                'margin: 1px 0;' +
            '}' +
            '.wl-footer-map-legend__dot {' +
                'width: 8px;' +
                'height: 8px;' +
                'border-radius: 50%;' +
                'flex-shrink: 0;' +
                'border: 1px solid rgba(0,0,0,0.2);' +
            '}' +
            // On very small screens, hide the legend (avoid covering map)
            '@media (max-width: 359px) {' +
                '.wl-footer-map-legend { display: none; }' +
            '}';
        document.head.appendChild(style);
        console.log('WL: footer popup color + legend overrides injected');
    })();

    // Warung Lakku cabang location (matches modal + wl_osm_enrichment)
    var WL_CABANG = { lat: -8.188092, lng: 112.356862, radiusM: 15000 };

    // ---- Lazy-load MapLibre via IntersectionObserver ----
    // Saves ~400KB of JS on pages where the user never scrolls
    // to the footer.
    function bootstrapFooterMap() {
        var container = document.getElementById('wl_footer_map');
        if (!container) return;
        if (container._wlMapInit) return;

        if (!('IntersectionObserver' in window)) {
            initFooterMap();
            return;
        }

        var io = new IntersectionObserver(function (entries) {
            entries.forEach(function (entry) {
                if (entry.isIntersecting) {
                    io.disconnect();
                    initFooterMap();
                }
            });
        }, { rootMargin: '300px' });
        io.observe(container);
    }

    function loadMapLibreScript(callback) {
        if (window.maplibregl) {
            callback();
            return;
        }
        if (window._wlMapLibreLoading) {
            window._wlMapLibreCallbacks = window._wlMapLibreCallbacks || [];
            window._wlMapLibreCallbacks.push(callback);
            return;
        }
        window._wlMapLibreLoading = true;
        window._wlMapLibreCallbacks = [callback];

        var link = document.createElement('link');
        link.rel = 'stylesheet';
        link.href = 'https://unpkg.com/maplibre-gl@4.7.1/dist/maplibre-gl.css';
        document.head.appendChild(link);

        var script = document.createElement('script');
        script.src = 'https://unpkg.com/maplibre-gl@4.7.1/dist/maplibre-gl.js';
        script.async = true;
        script.onload = function () {
            var cbs = window._wlMapLibreCallbacks;
            window._wlMapLibreCallbacks = [];
            for (var i = 0; i < cbs.length; i++) {
                try { cbs[i](); } catch (e) { console.warn(e); }
            }
        };
        document.head.appendChild(script);
    }

    function initFooterMap() {
        var container = document.getElementById('wl_footer_map');
        if (!container) return;
        if (container._wlMapInit) return;
        container._wlMapInit = true;

        loadMapLibreScript(function () {
            if (!window.maplibregl) {
                console.warn('WL: maplibregl failed to load');
                return;
            }

            container.innerHTML = '';

            var map = new maplibregl.Map({
                container: container,
                style: 'https://tiles.openfreemap.org/styles/liberty',
                center: [WL_CABANG.lng, WL_CABANG.lat],
                zoom: 12,
                bearing: 0,
                pitch: 0,
                maxPitch: 0,
                attributionControl: true,
                dragRotate: false,
                touchPitch: false,
                pitchWithRotate: false,
                touchZoomRotate: true,
                scrollZoom: false  // footer map: don't capture page scroll
            });

            try { map.touchZoomRotate.disableRotation(); } catch (e) {}
            try { map.keyboard.disableRotation(); } catch (e) {}
            map.on('rotate', function () {
                if (map.getBearing() !== 0) map.setBearing(0);
            });
            map.on('pitch', function () {
                if (map.getPitch() !== 0) map.setPitch(0);
            });

            map.on('load', function () {
                applyCustomMapStyle(map);
                addFooterCustomLayers(map);
                loadFooterEnrichment(map);
                // v3.10.25: add category legend overlay (must be
                // done after container.innerHTML='' which wipes
                // any static children added in the template)
                addFooterLegend(container);
            });
            map.on('styledata', function () {
                applyCustomMapStyle(map);
                addFooterCustomLayers(map);
            });

            // ---- Cabang marker (storefront icon + label + popup) ----
            var cabangEl = document.createElement('div');
            cabangEl.className = 'wl-cabang-marker';
            cabangEl.innerHTML =
                '<div class="wl-cabang-marker__pin">' +
                    '<i class="fa fa-shopping-bag"></i>' +
                '</div>' +
                '<div class="wl-cabang-marker__label">' +
                    '<strong>WARUNG LAKKU</strong>' +
                    '<span>Cabang Binangun</span>' +
                '</div>';

            var cabangPopup = new maplibregl.Popup({
                offset: 30,
                closeButton: true,
                closeOnClick: true
            }).setHTML(
                '<div style="min-width: 220px; font-family: Poppins, sans-serif; padding: 4px; color: #333;">' +
                    '<strong style="color: #7a0c14; font-size: 14px; display: block; margin-bottom: 2px;">' +
                        '<i class="fa fa-shopping-bag" style="color: #f5c400;"></i> WARUNG LAKKU' +
                    '</strong>' +
                    '<span style="color: #666; font-size: 11px; display: block; margin-bottom: 6px;">Cabang Binangun</span>' +
                    '<hr style="margin: 6px 0; border: 0; border-top: 1px solid #eee;"/>' +
                    '<div style="font-size: 12px; color: #333; line-height: 1.6;">' +
                        '<div style="margin-bottom: 4px;">' +
                            '<i class="fa fa-map-marker" style="color: #7a0c14; width: 14px;"></i> ' +
                            'Dusun Ngrekesan, Desa Ngadri, Kec. Binangun,<br/>' +
                            '<span style="margin-left: 18px;">Kab. Blitar, Jawa Timur 66193</span>' +
                        '</div>' +
                        '<div style="margin-bottom: 4px;">' +
                            '<i class="fa fa-whatsapp" style="color: #25d366; width: 14px;"></i> ' +
                            '<a href="https://wa.me/6285733556953" target="_blank" rel="noopener" style="color: #1976d2;">+62 857-3355-6953</a>' +
                        '</div>' +
                        '<div>' +
                            '<i class="fa fa-location-arrow" style="color: #7a0c14; width: 14px;"></i> ' +
                            '<a href="https://www.openstreetmap.org/?mlat=-8.188092&amp;mlon=112.356862#map=15/-8.188092/112.356862" target="_blank" rel="noopener" style="color: #1976d2;">-8.188092, 112.356862</a>' +
                        '</div>' +
                    '</div>' +
                '</div>'
            );

            new maplibregl.Marker({
                element: cabangEl,
                anchor: 'bottom',
                rotationAlignment: 'viewport',
                pitchAlignment: 'viewport'
            })
                .setLngLat([WL_CABANG.lng, WL_CABANG.lat])
                .setPopup(cabangPopup)
                .addTo(map);

            // Zoom controls (top-right, no compass)
            map.addControl(new maplibregl.NavigationControl({
                visualizePitch: false,
                showCompass: false,
                showZoom: true
            }), 'top-right');

            window._wl_footer_map = map;
            console.log('WL: footer MapLibre map initialized');
        });
    }

    // ---- helpers (duplicated from modal, scoped to footer IIFE) ----
    function applyCustomMapStyle(map) {
        if (!map || !map.getStyle) return;
        var layers = map.getStyle().layers || [];
        for (var i = 0; i < layers.length; i++) {
            var layer = layers[i];
            var sl = layer['source-layer'] || '';
            var lid = layer.id || '';

            if (layer.type === 'line' && sl === 'transportation') {
                var color = '#7a0c14';
                if (lid.indexOf('casing') !== -1) color = '#5a080e';
                else if (lid.indexOf('minor') !== -1 ||
                         lid.indexOf('path') !== -1 ||
                         lid.indexOf('pier') !== -1) color = '#a02030';
                try { map.setPaintProperty(lid, 'line-color', color); } catch (e) {}
            }

            if ((layer.type === 'fill' && sl === 'water') ||
                (layer.type === 'line' && sl === 'waterway')) {
                try {
                    if (layer.type === 'fill') {
                        map.setPaintProperty(lid, 'fill-color', '#cfe4f5');
                    } else {
                        map.setPaintProperty(lid, 'line-color', '#a8d0ed');
                    }
                } catch (e) {}
            }

            if (layer.type === 'fill' && sl === 'building') {
                try {
                    map.setPaintProperty(lid, 'fill-color', '#fff7e0');
                    map.setPaintProperty(lid, 'fill-opacity', 0.9);
                } catch (e) {}
            }

            if (layer.type === 'fill' && sl === 'landuse') {
                try { map.setPaintProperty(lid, 'fill-color', '#e8f5e8'); } catch (e) {}
            }

            if (layer.type === 'line' && sl === 'aeroway') {
                try { map.setPaintProperty(lid, 'line-color', '#b03040'); } catch (e) {}
            }

            if (layer.type === 'line' && sl === 'boundary') {
                try {
                    map.setPaintProperty(lid, 'line-color', '#7a0c14');
                    map.setPaintProperty(lid, 'line-opacity', 0.4);
                } catch (e) {}
            }
        }
    }

    function makeCircleGeoJSON(centerLat, centerLng, radiusM, segments) {
        var coords = [];
        var R = 6378137;
        for (var i = 0; i <= segments; i++) {
            var bearing = (i * 360 / segments) * Math.PI / 180;
            var lat1 = centerLat * Math.PI / 180;
            var lng1 = centerLng * Math.PI / 180;
            var dByR = radiusM / R;
            var lat2 = Math.asin(
                Math.sin(lat1) * Math.cos(dByR) +
                Math.cos(lat1) * Math.sin(dByR) * Math.cos(bearing));
            var lng2 = lng1 + Math.atan2(
                Math.sin(bearing) * Math.sin(dByR) * Math.cos(lat1),
                Math.cos(dByR) - Math.sin(lat1) * Math.sin(lat2));
            coords.push([lng2 * 180 / Math.PI, lat2 * 180 / Math.PI]);
        }
        return {
            type: 'Feature',
            geometry: { type: 'Polygon', coordinates: [coords] },
            properties: { radiusM: radiusM }
        };
    }

    function addFooterCustomLayers(map) {
        try {
            if (!map.getSource('wl-footer-cabang-radius')) {
                map.addSource('wl-footer-cabang-radius', {
                    type: 'geojson',
                    data: makeCircleGeoJSON(
                        WL_CABANG.lat, WL_CABANG.lng,
                        WL_CABANG.radiusM, 64)
                });
                map.addLayer({
                    id: 'wl-footer-cabang-radius-fill',
                    type: 'fill',
                    source: 'wl-footer-cabang-radius',
                    paint: {
                        'fill-color': '#7a0c14',
                        'fill-opacity': 0.06
                    }
                });
                map.addLayer({
                    id: 'wl-footer-cabang-radius-stroke',
                    type: 'line',
                    source: 'wl-footer-cabang-radius',
                    paint: {
                        'line-color': '#7a0c14',
                        'line-width': 1.5,
                        'line-dasharray': [4, 3],
                        'line-opacity': 0.7
                    }
                });
            }
        } catch (e) {
            console.warn('WL: footer cabang radius failed:', e.message);
        }
    }

    // v3.10.25: build POI category legend overlay and append
    // it to the map container. Must be called AFTER
    // container.innerHTML = '' in initFooterMap, otherwise
    // the legend gets wiped along with the loading placeholder.
    function addFooterLegend(container) {
        if (container.querySelector('.wl-footer-map-legend')) return;
        var legend = document.createElement('div');
        legend.className = 'wl-footer-map-legend';
        var rows = [
            ['#1976d2', 'Minimarket'],
            ['#2e7d32', 'Masjid/Tempat Ibadah'],
            ['#f57c00', 'Sekolah'],
            ['#c62828', 'SPBU'],
            ['#6a1b9a', 'Pasar'],
            ['#00838f', 'Kesehatan'],
            ['#546e7a', 'Lainnya']
        ];
        var html = '<span class="wl-footer-map-legend__title">Kategori POI</span>';
        for (var i = 0; i < rows.length; i++) {
            html += '<div class="wl-footer-map-legend__row">' +
                '<span class="wl-footer-map-legend__dot" style="background:' + rows[i][0] + '"/>' +
                '<span>' + rows[i][1] + '</span>' +
                '</div>';
        }
        legend.innerHTML = html;
        container.appendChild(legend);
        console.log('WL: footer map legend added');
    }

    function loadFooterEnrichment(map) {
        if (map._wlFooterEnrichmentLoaded) return;
        map._wlFooterEnrichmentLoaded = true;

        var COLOR_BY_CATEGORY = {
            'minimarket': '#1976d2',
            'masjid':     '#2e7d32',
            'sekolah':    '#f57c00',
            'spbu':       '#c62828',
            'pasar':      '#6a1b9a',
            'kesehatan':  '#00838f',
            'lainnya':    '#546e7a'
        };

        var url = '/api/osm/geojson/pois' +
            '?lat=' + encodeURIComponent(WL_CABANG.lat) +
            '&lon=' + encodeURIComponent(WL_CABANG.lng) +
            '&radius=5000&limit=300';
        fetch(url, { credentials: 'same-origin' })
            .then(function (r) { return r.json(); })
            .then(function (geojson) {
                if (!geojson || !geojson.features || !geojson.features.length) {
                    console.log('WL: footer enrichment POIs empty');
                    return;
                }
                if (map.getSource('wl-footer-enriched-pois')) return;
                map.addSource('wl-footer-enriched-pois', {
                    type: 'geojson',
                    data: geojson
                });

                var catCases = [];
                Object.keys(COLOR_BY_CATEGORY).forEach(function (cat) {
                    catCases.push(cat);
                    catCases.push(COLOR_BY_CATEGORY[cat]);
                });

                map.addLayer({
                    id: 'wl-footer-enriched-pois-circle',
                    type: 'circle',
                    source: 'wl-footer-enriched-pois',
                    minzoom: 11,
                    paint: {
                        'circle-radius': {
                            stops: [[11, 2.5], [13, 4], [15, 6], [17, 8]]
                        },
                        'circle-color': ['match',
                            ['get', 'landmark_category']
                        ].concat(catCases).concat(['#546e7a']),
                        'circle-stroke-color': '#ffffff',
                        'circle-stroke-width': 1.5,
                        'circle-opacity': 0.95
                    }
                });

                map.addLayer({
                    id: 'wl-footer-enriched-pois-label',
                    type: 'symbol',
                    source: 'wl-footer-enriched-pois',
                    minzoom: 13,
                    layout: {
                        'text-field': ['get', 'name'],
                        'text-size': {
                            stops: [[13, 9], [15, 11], [17, 13]]
                        },
                        'text-font': ['Noto Sans Bold'],
                        'text-offset': [0, 1.4],
                        'text-anchor': 'top',
                        'text-allow-overlap': false,
                        'text-ignore-placement': false
                    },
                    paint: {
                        'text-color': '#1a1a1a',
                        'text-halo-color': '#ffffff',
                        'text-halo-width': 2.5
                    }
                });

                // Popup on click
                var popup = new maplibregl.Popup({
                    closeButton: true,
                    closeOnClick: true,
                    offset: 10
                });
                map.on('click', 'wl-footer-enriched-pois-circle', function (e) {
                    if (!e.features || !e.features.length) return;
                    var f = e.features[0];
                    var p = f.properties || {};
                    // v3.10.25: explicit color:#333 on inner div so unwrapped
                    // text nodes (the values after each label) inherit dark
                    // color instead of footer white. Each value is also
                    // wrapped in a span with color:#333 for triple redundancy.
                    var html = '<div style="min-width:160px;font-family:sans-serif;font-size:12px;line-height:1.5;color:#333">';
                    html += '<strong style="font-size:13px;color:#7a0c14">' +
                            (p.name || '(tanpa nama)') + '</strong><br/>';
                    if (p.landmark_category) {
                        html += '<span style="color:#666">Kategori: </span>' +
                                '<span style="color:#333">' + p.landmark_category + '</span><br/>';
                    }
                    if (p.subtype) {
                        html += '<span style="color:#666">Tipe: </span>' +
                                '<span style="color:#333">' + p.subtype + '</span><br/>';
                    }
                    if (p.distance_m !== undefined && p.distance_m !== null) {
                        var distKm = (p.distance_m / 1000).toFixed(2);
                        html += '<span style="color:#666">Jarak: </span>' +
                                '<span style="color:#7a0c14;font-weight:700">' +
                                p.distance_m + ' m (' + distKm + ' km)</span>';
                    }
                    html += '</div>';
                    popup.setLngLat(f.geometry.coordinates)
                        .setHTML(html)
                        .addTo(map);
                });
                map.on('mouseenter', 'wl-footer-enriched-pois-circle', function () {
                    map.getCanvas().style.cursor = 'pointer';
                });
                map.on('mouseleave', 'wl-footer-enriched-pois-circle', function () {
                    map.getCanvas().style.cursor = '';
                });

                console.log('WL: footer enrichment POIs loaded: ' + geojson.features.length);
            })
            .catch(function (e) {
                console.warn('WL: footer enrichment POIs failed:', e);
            });
    }

    // ---- boot ----
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', bootstrapFooterMap);
    } else {
        bootstrapFooterMap();
    }
})();
